import sys
import heapq
from typing import List

class Solution:
    def mergeKLists(self, lists: List[List[int]]) -> List[int]:
        res = []
        pq = []
        for i, l in enumerate(lists):
            if l:
                heapq.heappush(pq, (l[0], i, 0))
        while pq:
            val, list_idx, elem_idx = heapq.heappop(pq)
            res.append(val)
            if elem_idx + 1 < len(lists[list_idx]):
                heapq.heappush(pq, (lists[list_idx][elem_idx + 1], list_idx, elem_idx + 1))
        return res

if __name__ == '__main__':
    tokens = sys.stdin.read().split()
    if not tokens:
        sys.exit(0)
    k = int(tokens[0])
    lists = []
    idx = 1
    for _ in range(k):
        n = int(tokens[idx])
        l = [int(x) for x in tokens[idx+1:idx+1+n]]
        lists.append(l)
        idx += 1 + n
    sol = Solution()
    ans = sol.mergeKLists(lists)
    print(len(ans))
    if ans:
        print(" ".join(map(str, ans)))

