#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
private:
    struct Element {
        int val;
        int list_idx;
        int elem_idx;
        bool operator>(const Element& other) const {
            return val > other.val;
        }
    };

public:
    vector<int> mergeKLists(vector<vector<int>>& lists) {
        vector<int> res;
        priority_queue<Element, vector<Element>, greater<Element>> pq;
        for (int i = 0; i < lists.size(); i++) {
            if (!lists[i].empty()) {
                pq.push({lists[i][0], i, 0});
            }
        }
        while (!pq.empty()) {
            Element curr = pq.top();
            pq.pop();
            res.push_back(curr.val);
            if (curr.elem_idx + 1 < lists[curr.list_idx].size()) {
                pq.push({lists[curr.list_idx][curr.elem_idx + 1], curr.list_idx, curr.elem_idx + 1});
            }
        }
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int k;
    if (!(cin >> k)) return 0;
    vector<vector<int>> lists(k);
    for (int i = 0; i < k; i++) {
        int n;
        if (!(cin >> n)) return 0;
        lists[i].resize(n);
        for (int j = 0; j < n; j++) {
            cin >> lists[i][j];
        }
    }
    Solution sol;
    vector<int> ans = sol.mergeKLists(lists);
    cout << ans.size() << "\n";
    if (!ans.empty()) {
        for (int i = 0; i < ans.size(); i++) {
            cout << ans[i] << (i == ans.size() - 1 ? "" : " ");
        }
        cout << "\n";
    }
    return 0;
}
